mapper.select:
select 
from exam


        and name like concat('%', #{name}, '%')


        and course_id = #{courseId}


        and teacher_id = #{teacherId}


        and status = #{status}


order by create_time desc

mapper.update:
update exam
name = #{name}, paper_id = #{paperId}, paper_name = #{paperName}, start_time = #{startTime}, end_time = #{endTime}, duration = #{duration}, total_score = #{totalScore}, description = #{description}, status = #{status},
where id = #{id}
